// ─── Edit these to match your users' target roles ─────────────────
const ROLES = [
  'Software Engineer',
  'Backend Developer',
  'Frontend Developer',
  'Full Stack Developer',
  'DevOps Engineer',
  'Data Scientist',
];
const LOCATION = 'Israel';
// ──────────────────────────────────────────────────────────────────
return ROLES.map(role => ({ json: { role, location: LOCATION } }));

// Parse LinkedIn HTML job cards
const html = $input.first().json.data || '';
const jobs = [];
const blocks = html.split(/<li[^>]*>/).slice(1);

for (const block of blocks) {
  const titleMatch = block.match(/class="base-search-card__title"[^>]*>([\s\S]*?)<\/h3>/i);
  if (!titleMatch) continue;
  const title = titleMatch[1].replace(/<[^>]+>/g, '').trim();
  if (!title || title.length < 2) continue;

  const compMatch = block.match(/class="base-search-card__subtitle"[\s\S]*?>([^<]+)</);
  const company = compMatch ? compMatch[1].trim() : '';

  const locMatch = block.match(/class="job-search-card__location"[^>]*>([\s\S]*?)<\/span>/i);
  const location = locMatch ? locMatch[1].replace(/<[^>]+>/g, '').trim() : '';

  const urlMatch = block.match(/href="(https:\/\/[^"]*linkedin\.com\/jobs\/view\/[^"]+)"/i);
  let url = urlMatch ? urlMatch[1].replace(/&amp;/g, '&') : '';
  if (url.includes('?')) url = url.split('?')[0];

  jobs.push({ title, company, location, url, source: 'linkedin' });
}

return jobs.map(job => ({ json: job }));

// Collect all jobs from all role-fetches, deduplicate by URL
const jobs = $input.all().map(item => item.json);
const unique = [];
const seen = new Set();
for (const job of jobs) {
  const key = job.url || (job.title + '|' + job.company);
  if (key && !seen.has(key)) {
    seen.add(key);
    unique.push(job);
  }
}
return [{ json: { source: 'linkedin', jobs: unique } }];
